importancehigh 08 style 08·1 #text *§1/* DayPicker styles */

.cascoon-DayPicker {
  display: inline-block !important;
  font-size: 1rem !important;
}

.cascoon-DayPicker-wrapper {
  position: relative !important;

  flex-direction: row !important;
  padding-bottom: 1em !important;

  -webkit-user-select: none !important;

     -moz-user-select: none !important;

      -ms-user-select: none !important;

          user-select: none !important;
}

.cascoon-DayPicker-Months {
  display: flex !important;
  flex-wrap: wrap !important;
  justify-content: center !important;
}

.cascoon-DayPicker-Month {
  display: table !important;
  margin: 0 1em !important;
  margin-top: 1em !important;
  border-spacing: 0 !important;
  border-collapse: collapse !important;

  -webkit-user-select: none !important;

     -moz-user-select: none !important;

      -ms-user-select: none !important;

          user-select: none !important;
}

.cascoon-DayPicker-NavBar {
}

.cascoon-DayPicker-NavButton {
  position: absolute !important;
  top: 1em !important;
  right: 1.5em !important;
  left: auto !important;

  display: inline-block !important;
  margin-top: 2px !important;
  width: 1.25em !important;
  height: 1.25em !important;
  background-position: center !important;
  background-size: 50% !important;
  background-repeat: no-repeat !important;
  color: #8B9898 !important;
  cursor: pointer !important;
}

.cascoon-DayPicker-NavButton:hover {
  opacity: 0.8 !important;
}

.cascoon-DayPicker-NavButton--prev {
  margin-right: 1.5em !important;
  background-image: url('data:image/png;base64,') !important;
}

.cascoon-DayPicker-NavButton--next {
  background-image: url('data:image/png;base64,') !important;
}

.cascoon-DayPicker-NavButton--interactionDisabled {
  display: none !important;
}

.cascoon-DayPicker-Caption {
  display: table-caption !important;
  margin-bottom: 0.5em !important;
  padding: 0 0.5em !important;
  text-align: left !important;
}

.cascoon-DayPicker-Caption > div {
  font-weight: 500 !important;
  font-size: 1.15em !important;
}

.cascoon-DayPicker-Weekdays {
  display: table-header-group !important;
  margin-top: 1em !important;
}

.cascoon-DayPicker-WeekdaysRow {
  display: table-row !important;
}

.cascoon-DayPicker-Weekday {
  display: table-cell !important;
  padding: 0.5em !important;
  color: #8B9898 !important;
  text-align: center !important;
  font-size: 0.875em !important;
}

.cascoon-DayPicker-Weekday abbr[title] {
  border-bottom: none !important;
  text-decoration: none !important;
}

.cascoon-DayPicker-Body {
  display: table-row-group !important;
}

.cascoon-DayPicker-Week {
  display: table-row !important;
}

.cascoon-DayPicker-Day {
  display: table-cell !important;
  padding: 0.5em !important;
  border-radius: 50% !important;
  vertical-align: middle !important;
  text-align: center !important;
  cursor: pointer !important;
}

.cascoon-DayPicker-WeekNumber {
  display: table-cell !important;
  padding: 0.5em !important;
  min-width: 1em !important;
  border-right: 1px solid #EAECEC !important;
  color: #8B9898 !important;
  vertical-align: middle !important;
  text-align: right !important;
  font-size: 0.75em !important;
  cursor: pointer !important;
}

.cascoon-DayPicker--interactionDisabled .cascoon-DayPicker-Day {
  cursor: default !important;
}

.cascoon-DayPicker-Footer {
  padding-top: 0.5em !important;
}

.cascoon-DayPicker-TodayButton {
  border: none !important;
  background-color: transparent !important;
  background-image: none !important;
  box-shadow: none !important;
  color: #4A90E2 !important;
  font-size: 0.875em !important;
  cursor: pointer !important;
}

/* Default modifiers */

.cascoon-DayPicker-Day--today {
  color: #D0021B !important;
  font-weight: 700 !important;
}

.cascoon-DayPicker-Day--outside {
  color: #8B9898 !important;
  cursor: default !important;
}

.cascoon-DayPicker-Day--disabled {
  color: #DCE0E0 !important;
  cursor: default !important;
  /* background-color: #eff1f1; */
}

/* Example modifiers */

.cascoon-DayPicker-Day--sunday {
  background-color: #F7F8F8 !important;
}

.cascoon-DayPicker-Day--sunday:not(.cascoon-DayPicker-Day--today) {
  color: #DCE0E0 !important;
}

.cascoon-DayPicker-Day--selected:not(.cascoon-DayPicker-Day--disabled):not(.cascoon-DayPicker-Day--outside) {
  position: relative !important;

  background-color: #4A90E2 !important;
  color: #F0F8FF !important;
}

.cascoon-DayPicker-Day--selected:not(.cascoon-DayPicker-Day--disabled):not(.cascoon-DayPicker-Day--outside):hover {
  background-color: #51A0FA !important;
}

.cascoon-DayPicker:not(.cascoon-DayPicker--interactionDisabled)
  .cascoon-DayPicker-Day:not(.cascoon-DayPicker-Day--disabled):not(.cascoon-DayPicker-Day--selected):not(.cascoon-DayPicker-Day--outside):hover {
  background-color: #F0F8FF !important;
}

/* DayPickerInput */

.cascoon-DayPickerInput {
  display: inline-block !important;
}

.cascoon-DayPickerInput-OverlayWrapper {
  position: relative !important;
}

.cascoon-DayPickerInput-Overlay {
  position: absolute !important;
  left: 0 !important;
  z-index: 1 !important;

  background: white !important;
  box-shadow: 0 2px 5px rgba(0, 0, 0, 0.15) !important;
}
